import './App.css';
import Nav from "./Componants/Nav";
import Intro from "./Componants/Intro";
import WelcomePage from "./Componants/welcome"; // Ensure correct path

function App() {
  return (
    <div className="App">
      {/* Render Navigation Bar */}
      <Nav />

      {/* Render Intro Section */}
      <Intro />

      {/* Render Welcome Page */}
      <WelcomePage />
    </div>
  );
}

export default App;
